const c = $json;

const riskColor = c.Risk_Flag === 'Critical' ? '#D32F2F' : '#F57C00';
const riskEmoji = c.Risk_Flag === 'Critical' ? '🔴' : '🟡';

const html = `<!DOCTYPE html><html><head><style>
body{font-family:Arial,sans-serif;padding:30px;color:#222;max-width:700px}
h1{color:${riskColor}} h2{color:#444;font-size:16px}
table{width:100%;border-collapse:collapse;margin:16px 0}
th{background:#333;color:#fff;padding:8px;text-align:left;font-size:13px}
td{padding:8px;border-bottom:1px solid #eee;font-size:13px}
.badge{display:inline-block;padding:4px 12px;border-radius:12px;font-weight:bold;
color:#fff;background:${riskColor};font-size:13px}
.metric{background:#f9f9f9;padding:12px;border-radius:8px;margin:8px 0}
</style></head><body>
<h1>${riskEmoji} Financial Health Alert — ${c.Company_Name}</h1>
<p>Week: <strong>${c.Reporting_Week}</strong> &nbsp;|&nbsp; 
Status: <span class="badge">${c.Risk_Flag}</span></p>
<h2>Key Financial Ratios</h2>
<table>
<tr><th>Metric</th><th>Value</th><th>Benchmark</th><th>Status</th></tr>
<tr><td>Current Ratio</td><td>${c.Current_Ratio}</td><td>&gt; 1.5</td>
<td>${c.Current_Ratio < 1.0 ? '🔴 Critical' : c.Current_Ratio < 1.5 ? '🟡 Watch' : '🟢 OK'}</td></tr>
<tr><td>Debtor Days</td><td>${c.Debtor_Days}</td><td>&lt; 55 days</td>
<td>${c.Debtor_Days > 75 ? '🔴 Critical' : c.Debtor_Days > 55 ? '🟡 Watch' : '🟢 OK'}</td></tr>
<tr><td>Gross Margin</td><td>${c.Gross_Margin_Pct}%</td><td>&gt; 35%</td>
<td>${c.Gross_Margin_Pct < 25 ? '🔴 Critical' : c.Gross_Margin_Pct < 35 ? '🟡 Watch' : '🟢 OK'}</td></tr>
<tr><td>Cash Runway</td><td>${c.Weeks_Cash_Runway} weeks</td><td>&gt; 8 weeks</td>
<td>${c.Weeks_Cash_Runway < 4 ? '🔴 Critical' : c.Weeks_Cash_Runway < 8 ? '🟡 Watch' : '🟢 OK'}</td></tr>
</table>
<p style="color:#666;font-size:12px">Generated automatically by Financial Health Monitor</p>
</body></html>`;

return { json: { ...c, html } };

const c = $json;

const issues = [];
if (c.Current_Ratio < 1.0) issues.push(`critically low liquidity (current ratio: ${c.Current_Ratio})`);
else if (c.Current_Ratio < 1.5) issues.push(`below-benchmark liquidity (current ratio: ${c.Current_Ratio})`);
if (c.Debtor_Days > 75) issues.push(`severely extended debtor collection (${c.Debtor_Days} days)`);
else if (c.Debtor_Days > 55) issues.push(`slow debtor collection (${c.Debtor_Days} days)`);
if (c.Gross_Margin_Pct < 25) issues.push(`critically compressed gross margin (${c.Gross_Margin_Pct}%)`);
else if (c.Gross_Margin_Pct < 35) issues.push(`below-target gross margin (${c.Gross_Margin_Pct}%)`);
if (c.Weeks_Cash_Runway < 4) issues.push(`dangerously low cash runway (${c.Weeks_Cash_Runway} weeks)`);
else if (c.Weeks_Cash_Runway < 8) issues.push(`constrained cash runway (${c.Weeks_Cash_Runway} weeks)`);

const urgency = c.Risk_Flag === 'Critical' 
  ? 'Immediate escalation recommended.' 
  : 'Schedule a review within 2 weeks.';

const advisory = `${c.Company_Name} is showing ${issues.join(' and ')} as of ${c.Reporting_Week}. ${urgency} Relationship manager should contact the client to discuss remediation options including debtor acceleration, cost reduction, or emergency credit facilities.`;

return { json: { ...c, advisory } };
